#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
const int b=113,maxn=1e6+5;
int h[maxn],p[maxn],len[15],sum[15][maxn];
void init_hash(const string &s) {
	int n=s.length();
	p[0]=1;
	for(int i=1; i<=n; i++) {
		p[i]=p[i-1]*b;
		h[i]=h[i-1]*b+s[i-1];
	}
}
int get_hash(int l,int r) {
	return h[r]-h[l-1]*p[r-l+1];
}
int n,q,m;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	string s;
	cin>>m>>q>>s;
	init_hash(s);
	n=s.length();
	for(int i=1;i<=m;i++){
		string x;
		cin>>x;
		len[i]=x.length();
		int u=0;
		for(auto c:x){
			u=u*b+c;
		}
		for(int j=1;j<=n;j++){
			if(i>=len[i],get_hash(j-len[i]+1,j)==u){
				sum[i][j]++;
			}
			sum[i][j]+=sum[i][j-1];
		}
	}
	while(q--){
		int l,r;
		cin>>l>>r;
		int ans=0;
		for(int i=1;i<=m;i++){
			int sx=l+len[i]-1;
			if(sx<=r){
				ans+=sum[i][r]-sum[i][sx-1];
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
